// Zigbee
package zigbeemanager

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40032/idl"
	"github.com/arminguenther/xeruspower-go/v40032/idl/event"
	"github.com/arminguenther/xeruspower-go/v40032/zigbee/zigbeedevice"
)

// Error Codes
const (
	ERR_DEVICE_EXISTS      int32 = 1
	ERR_MAX_DEVICE_REACHED int32 = 2
	ERR_DEVICE_NOT_FOUND   int32 = 3
	ERR_INVALID_PARAMS     int32 = 4
	ERR_INVALID_KEY        int32 = 5
	ERR_INVALID_CHANNEL    int32 = 6
)

// Zigbee Manager
type ZigbeeManager interface {
	idl.Object

	// Retrieve Dongle MetaData
	//
	//	@return MetaData
	GetMetaData(ctx context.Context) (MetaData, error)

	// Retrieve Dongle State
	//
	//	@return DongleState
	GetDongleState(ctx context.Context) (DongleState, error)

	// Retrieve Dongle Settings
	//
	//	@return Settings
	GetSettings(ctx context.Context) (Settings, error)

	// Set Dongle Settings
	//
	//	@return 0                 if OK
	//	@return ERR_INVALID_CHANNEL if the channel is invalid
	//	@return ERR_INVALID_PARAMS if any parameters are invalid
	SetSettings(ctx context.Context, settings Settings) (int32, error)

	// Add new devices
	//
	// Return codes:
	// 0                 if OK
	// ERR_DEVICE_EXISTS if device is already in list
	// ERR_MAX_DEVICE_REACHED if the max device limit reached
	// ERR_INVALID_KEY if the key is wrong
	// ERR_INVALID_PARAMS if the entered data is invalid
	//
	//	@return List of return codes for each device
	AddDevices(ctx context.Context, sensors []DeviceRegistration) ([]int32, error)

	// Remove a device
	//
	//	@return 0                 if OK
	//	@return ERR_DEVICE_NOT_FOUND if device is not registered
	RemoveDevice(ctx context.Context, sourceId int32) (int32, error)

	// Get the list of registered devices
	//
	//	@return List of all registered devices
	GetRegisteredDevices(ctx context.Context) ([]zigbeedevice.ZigbeeDevice, error)
}

// States for the dongle
type DongleState int

const (
	NOT_INIT         DongleState = iota // no dongle
	READY                               // default state if no action in progress
	ERROR                               // something wrong
	INIT_IN_PROGRESS                    // dongle init in progress
	FW_UPGRADE                          // firmware upgrade
	IN_MODEM_STATE                      // receiving state for fw update
)

// Dongle MetaData
type MetaData struct {
	FirmwareVersion string // the current firmware version
	StackVersion    string // the current stack version
}

type Settings struct {
	Channel int32 // channel between 11 and 26 or 0xFF for auto search
}

// Device Registration
type DeviceRegistration struct {
	SourceId int32  // the source id to add
	Key      string // the OOB key (including CRC16)
	Slot     int32  // the preferred slot. 0xFFFF for auto manage
}

// Base Event
type DeviceEvent interface {
	event.Event
	SourceId() int32 // the device which is affected by the event
	isDeviceEvent()
}

// A sensor was added
type DeviceAddedEvent interface {
	DeviceEvent
	isDeviceAddedEvent()
}

// A sensor was removed
type DeviceRemovedEvent interface {
	DeviceEvent
	isDeviceRemovedEvent()
}

// Settings changed
type SettingsChangedEvent interface {
	event.Event
	OldSettings() Settings // the old settings
	NewSettings() Settings // the new settings
	isSettingsChangedEvent()
}

// State changed
type StateChangedEvent interface {
	event.Event
	OldState() DongleState // the old state
	NewState() DongleState // the new state
	isStateChangedEvent()
}
